						disabled={isUpdating}
					>
						<ShieldOff className="h-3.5 w-3.5 mr-1" />
						Spam
					</Button>
					<Button
						size="sm"
						variant="outline"
						className="h-7 text-xs text-destructive border-destructive/30 hover:bg-destructive/5"
						onClick={onDelete}
						disabled={isDeleting}
					>
						<Trash2 className="h-3.5 w-3.5 mr-1" />
						Delete
					</Button>
				</div>
			</div>
		</div>
	);
