"use client";

import { lazy, Suspense } from "react";
import { ComposedRoute } from "@btst/stack/client/components";
import { usePluginOverrides } from "@btst/stack/context";
import type { CommentsPluginOverrides } from "../../overrides";
import { useRouteLifecycle } from "@/hooks/use-route-lifecycle";

const ResourceCommentsPageInternal = lazy(() =>
	import("./resource-comments-page.internal").then((m) => ({
		default: m.ResourceCommentsPage,
	})),
);

function ResourceCommentsSkeleton() {
	return (
		<div className="w-full max-w-3xl space-y-4 animate-pulse">
			<div className="h-8 w-48 rounded bg-muted" />
			<div className="h-4 w-64 rounded bg-muted" />
			<div className="rounded-lg border h-32 bg-muted" />
		</div>
	);
}

export function ResourceCommentsPageComponent({
	resourceId,
	resourceType,
}: {
	resourceId: string;
	resourceType: string;
}) {
	return (
		<ComposedRoute
			path={`/comments/${resourceType}/${resourceId}`}
			PageComponent={() => (
				<ResourceCommentsPageWrapper
					resourceId={resourceId}
					resourceType={resourceType}
				/>
			)}
			LoadingComponent={ResourceCommentsSkeleton}
			onError={(error) =>
				console.error("[btst/comments] Resource comments error:", error)
			}
		/>
	);
}

function ResourceCommentsPageWrapper({
	resourceId,
	resourceType,
}: {
	resourceId: string;
	resourceType: string;
}) {
	const overrides = usePluginOverrides<CommentsPluginOverrides>("comments");

	useRouteLifecycle({
		routeName: "resourceComments",
		context: {
			path: `/comments/${resourceType}/${resourceId}`,
			params: { resourceId, resourceType },
			isSSR: typeof window === "undefined",
		},
		overrides,
		beforeRenderHook: (o, context) => {
			if (o.onBeforeResourceCommentsRendered) {
				return o.onBeforeResourceCommentsRendered(
					resourceType,
					resourceId,
					context,
				);
			}
			return true;
		},
	});

	return (
		<div className="w-full p-4 md:p-6 lg:p-8 flex flex-col items-start">
			<Suspense fallback={<ResourceCommentsSkeleton />}>
				<ResourceCommentsPageInternal
					resourceId={resourceId}
					resourceType={resourceType}
					apiBaseURL={overrides.apiBaseURL}
					apiBasePath={overrides.apiBasePath}
					headers={overrides.headers as HeadersInit | undefined}
				/>
			</Suspense>
		</div>
	);
}

/**
 * Context passed to lifecycle hooks
 */
export interface RouteContext {
	/** Current route path */
	path: string;
	/** Route parameters (e.g., { resourceId: "my-post", resourceType: "blog-post" }) */
	params?: Record<string, string>;
	/** Whether rendering on server (true) or client (false) */
	isSSR: boolean;
	/** Additional context properties */
	[key: string]: unknown;
}

/**
 * Overridable configuration and hooks for the Comments plugin.
 *
 * Provide these in the layout wrapping your pages via `PluginOverridesProvider`.
 */
export interface CommentsPluginOverrides {
	/**
	 * Base URL for API calls (e.g., "https://example.com")
	 */
	apiBaseURL: string;

	/**
	 * Path where the API is mounted (e.g., "/api/data")
	 */
	apiBasePath: string;

	/**
	 * Optional headers for authenticated API calls (e.g., forwarding cookies)
	 */
	headers?: Record<string, string>;

	// ============ Access Control Hooks ============

	/**
	 * Called before the moderation dashboard page is rendered.
	 * Return false to block rendering (e.g., redirect to login or show 403).
	 * @param context - Route context
	 */
	onBeforeModerationPageRendered?: (context: RouteContext) => boolean;

	/**
	 * Called before the per-resource comments page is rendered.
	 * Return false to block rendering (e.g., for authorization).
	 * @param resourceType - The type of resource (e.g., "blog-post")
	 * @param resourceId - The ID of the resource
	 * @param context - Route context
	 */
	onBeforeResourceCommentsRendered?: (
		resourceType: string,
		resourceId: string,
		context: RouteContext,
	) => boolean;

	// ============ Lifecycle Hooks ============

	/**
	 * Called when a route is rendered.
	 * @param routeName - Name of the route (e.g., 'moderation', 'resourceComments')
	 * @param context - Route context
	 */
	onRouteRender?: (
		routeName: string,
		context: RouteContext,
	) => void | Promise<void>;

	/**
	 * Called when a route encounters an error.
	 * @param routeName - Name of the route
	 * @param error - The error that occurred
	 * @param context - Route context
	 */
	onRouteError?: (
		routeName: string,
		error: Error,
		context: RouteContext,
	) => void | Promise<void>;
}

"use client";

import { useEffect, useRef, useState, type ReactNode } from "react";

export interface WhenVisibleProps {
	/** Content to render once the element scrolls into view */
	children: ReactNode;
	/** Optional placeholder rendered before the element enters the viewport */
	fallback?: ReactNode;
	/** IntersectionObserver threshold (0–1). Defaults to 0 (any pixel visible). */
	threshold?: number;
	/** Root margin passed to IntersectionObserver. Defaults to "200px" to preload slightly early. */
	rootMargin?: string;
	/** Additional className applied to the sentinel wrapper div */
	className?: string;
}

/**
 * Lazy-mounts children only when the sentinel element scrolls into the viewport.
 * Once mounted, children remain mounted even if the element scrolls out of view.
 *
 * Use this to defer expensive renders (comment threads, carousels, etc.) until
 * the user actually scrolls to that section.
 */
export function WhenVisible({
	children,
	fallback = null,
	threshold = 0,
	rootMargin = "200px",
	className,
}: WhenVisibleProps) {
	const [isVisible, setIsVisible] = useState(false);
	const sentinelRef = useRef<HTMLDivElement>(null);

	useEffect(() => {
		const el = sentinelRef.current;
		if (!el) return;

		// If IntersectionObserver is not available (SSR/old browsers), show immediately
		if (typeof IntersectionObserver === "undefined") {
			setIsVisible(true);
			return;
		}

		const observer = new IntersectionObserver(
			(entries) => {
				const entry = entries[0];
				if (entry?.isIntersecting) {
					setIsVisible(true);
					observer.disconnect();
				}
			},
			{ threshold, rootMargin },
		);

		observer.observe(el);
		return () => observer.disconnect();
	}, [threshold, rootMargin]);

	return (
		<div ref={sentinelRef} className={className}>
			{isVisible ? children : fallback}
		</div>
	);
}

"use client";

import { useEffect } from "react";

/**
 * Base route context interface that plugins can extend
 */
export interface BaseRouteContext {
	/** Current route path */
	path: string;
	/** Route parameters (e.g., { slug: "my-post" }) */
	params?: Record<string, string>;
	/** Whether rendering on server (true) or client (false) */
	isSSR: boolean;
	/** Additional context properties */
	[key: string]: unknown;
}

/**
 * Minimum interface required for route lifecycle hooks
 * Plugin overrides should implement these optional hooks
 */
export interface RouteLifecycleOverrides<TContext extends BaseRouteContext> {
	/** Called when a route is rendered */
	onRouteRender?: (
		routeName: string,
		context: TContext,
	) => void | Promise<void>;
	/** Called when a route encounters an error */
	onRouteError?: (
		routeName: string,
		error: Error,
		context: TContext,
	) => void | Promise<void>;
}

/**
 * Hook to handle route lifecycle events
 * - Calls authorization check before render
 * - Calls onRouteRender on mount
 * - Handles errors with onRouteError
 *
 * @example
 * ```tsx
 * const overrides = usePluginOverrides<MyPluginOverrides>("myPlugin");
 *
 * useRouteLifecycle({
 *   routeName: "dashboard",
 *   context: { path: "/dashboard", isSSR: typeof window === "undefined" },
 *   overrides,
 *   beforeRenderHook: (overrides, context) => {
 *     if (overrides.onBeforeDashboardRendered) {
 *       return overrides.onBeforeDashboardRendered(context);
 *     }
 *     return true;
 *   },
 * });
 * ```
 */
export function useRouteLifecycle<
	TContext extends BaseRouteContext,
	TOverrides extends RouteLifecycleOverrides<TContext>,
>({
	routeName,
	context,
	overrides,
	beforeRenderHook,
}: {
	routeName: string;
	context: TContext;
	overrides: TOverrides;
	beforeRenderHook?: (overrides: TOverrides, context: TContext) => boolean;
}) {
	// Authorization check - runs synchronously before render
	if (beforeRenderHook) {
		const canRender = beforeRenderHook(overrides, context);
		if (!canRender) {
			const error = new Error(`Unauthorized: Cannot render ${routeName}`);
			// Call error hook synchronously
			if (overrides.onRouteError) {
				try {
					const result = overrides.onRouteError(routeName, error, context);
					if (result instanceof Promise) {
						result.catch(() => {}); // Ignore promise rejection
					}
				} catch {
					// Ignore errors in error hook
				}
			}
			throw error;
		}
	}

	// Lifecycle hook - runs on mount
	useEffect(() => {
		if (overrides.onRouteRender) {
			try {
				const result = overrides.onRouteRender(routeName, context);
				if (result instanceof Promise) {
					result.catch((error) => {
						// If onRouteRender throws, call onRouteError
						if (overrides.onRouteError) {
							overrides.onRouteError(routeName, error, context);
						}
					});
				}
			} catch (error) {
				// If onRouteRender throws, call onRouteError
				if (overrides.onRouteError) {
					overrides.onRouteError(routeName, error as Error, context);
				}
			}
		}
	}, [routeName, overrides, context]);
}
